import{_ as a,o as e,c as o,a0 as i}from"./chunks/framework.BU6BaNeX.js";const h=JSON.parse('{"title":"Aspect Ratio & Orientation","description":"Configure custom print/screen orientations and auto-fit your maps without any empty padding or margins.","frontmatter":{"title":"Aspect Ratio & Orientation","description":"Configure custom print/screen orientations and auto-fit your maps without any empty padding or margins."},"headers":[],"relativePath":"api/orientation.md","filePath":"api/orientation.md"}'),n={name:"api/orientation.md"};function r(s,t,d,c,p,u){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="aspect-ratio-orientation" tabindex="-1">Aspect Ratio &amp; Orientation <a class="header-anchor" href="#aspect-ratio-orientation" aria-label="Permalink to &quot;Aspect Ratio &amp; Orientation&quot;">​</a></h1><p>Geospatial data comes in all shapes and sizes. <code>geoplot-themes</code> takes the headache out of bounding boxes and aspect ratios.</p><h2 id="the-orientation-parameter" tabindex="-1">The <code>orientation</code> Parameter <a class="header-anchor" href="#the-orientation-parameter" aria-label="Permalink to &quot;The `orientation` Parameter&quot;">​</a></h2><p>You control the canvas size using the <code>orientation</code> parameter.</p><h3 id="orientation-auto-recommended" tabindex="-1"><code>orientation=&quot;auto&quot;</code> (Recommended) <a class="header-anchor" href="#orientation-auto-recommended" aria-label="Permalink to &quot;`orientation=&quot;auto&quot;` (Recommended)&quot;">​</a></h3><p>When you use <code>&quot;auto&quot;</code>, the engine calculates the exact geographic bounding box of your data (the aspect ratio of the coordinates). It then dynamically sizes the final image to perfectly hug your data.</p><p><strong>Result</strong>: Zero white padding around your map.</p><h3 id="orientation-landscape" tabindex="-1"><code>orientation=&quot;landscape&quot;</code> <a class="header-anchor" href="#orientation-landscape" aria-label="Permalink to &quot;`orientation=&quot;landscape&quot;`&quot;">​</a></h3><p>Forces the final canvas to be a landscape rectangle (roughly 1.414 aspect ratio, similar to A4 paper). If your data is square or portrait, this <em>will</em> result in white padding on the sides.</p><h3 id="orientation-portrait" tabindex="-1"><code>orientation=&quot;portrait&quot;</code> <a class="header-anchor" href="#orientation-portrait" aria-label="Permalink to &quot;`orientation=&quot;portrait&quot;`&quot;">​</a></h3><p>Forces the final canvas to be a tall rectangle. Best used if you intend to print on standard letter/A4 portrait pages.</p>',11)])])}const m=a(n,[["render",r]]);export{h as __pageData,m as default};
